import type { Metadata } from "next";
import BusRouteSearchClient from "./BusRouteSearchClient";

export const metadata: Metadata = {
  title: "経路検索・運賃案内 | バスでGO",
  description:
    "渋谷駅 → 等々力 のバス経路を検索。速い・安い・乗換少で経路候補を比較し、徒歩〜乗車〜乗換の区間と運賃、次のバスまでの時間を確認できます。",
};

// Server Component shell. すべての対話 UI（onValueChange / onSelect / formatValue
// などの function props）は "use client" の BusRouteSearchClient 側に閉じ込めて
// あるので `next build`（RSC）が壊れない。
export default function BusRouteSearchPage() {
  return (
    <main className="min-h-screen bg-muted/30 text-foreground">
      <div className="mx-auto w-full max-w-md bg-background">
        <BusRouteSearchClient />
      </div>
    </main>
  );
}

"use client";

import * as React from "react";
import {
  IconArrowsUpDown,
  IconMapPin,
  IconFlag,
  IconClock,
  IconWalk,
  IconBus,
  IconHourglassLow,
  IconArrowRight,
  IconBookmark,
  IconBookmarkFilled,
  IconRefresh,
  IconChevronRight,
} from "@tabler/icons-react";

import {
  PageHeader,
  FilterChips,
  ListCard,
  Itinerary,
  AmountBreakdown,
  Badge,
  Button,
  Separator,
  ToggleGroup,
  ToggleGroupItem,
  type ItineraryItem,
  type AmountLine,
} from "@gunjo/ui";

import {
  CANDIDATES,
  ORIGIN,
  DESTINATION,
  SORT_TABS,
  sortCandidates,
  type RouteCandidate,
  type Leg,
  type SortKey,
} from "./data";

/* ------------------------------------------------------------------ */
/* helpers                                                             */
/* ------------------------------------------------------------------ */

const BADGE_LABEL: Record<
  NonNullable<RouteCandidate["badges"]>[number],
  { label: string; variant: "success" | "info" | "warning" | "default" }
> = {
  recommended: { label: "おすすめ", variant: "default" },
  fastest: { label: "最速", variant: "info" },
  cheapest: { label: "最安", variant: "success" },
  fewest: { label: "乗換少", variant: "warning" },
};

function fmtYen(n: number): string {
  return `${n.toLocaleString("ja-JP")}円`;
}

function transferLabel(n: number): string {
  return n === 0 ? "直通" : `乗換 ${n}回`;
}

/** Small line-系統 chip used inside the candidate leading slot. */
function LineChip({ children }: { children: React.ReactNode }) {
  return (
    <span className="inline-flex h-6 min-w-9 items-center justify-center rounded-md border border-primary/40 bg-primary/10 px-1.5 text-xs font-semibold tabular-nums text-foreground">
      {children}
    </span>
  );
}

/* ------------------------------------------------------------------ */
/* leg → Itinerary item                                               */
/* ------------------------------------------------------------------ */

function legToItem(leg: Leg, idx: number): ItineraryItem {
  if (leg.kind === "walk") {
    return {
      id: idx,
      tone: "muted",
      icon: <IconWalk className="size-4" />,
      time: `徒歩 ${leg.durationMin}分`,
      title: <span className="text-sm font-normal text-muted-foreground">{leg.toName}</span>,
      description: leg.note,
    };
  }
  if (leg.kind === "wait") {
    return {
      id: idx,
      tone: "warning",
      icon: <IconHourglassLow className="size-4" />,
      time: `乗換待ち ${leg.durationMin}分`,
      title: <span className="text-sm">{leg.fromName} で乗換</span>,
      description:
        leg.delayMin && leg.delayMin > 0
          ? `${leg.note ?? "乗換"}（遅延 約${leg.delayMin}分）`
          : leg.note,
    };
  }
  // ride
  return {
    id: idx,
    tone: "primary",
    icon: <IconBus className="size-4" />,
    time: `${leg.startAt} → ${leg.endAt}・${leg.durationMin}分`,
    title: (
      <span className="flex flex-wrap items-center gap-1.5">
        <LineChip>{leg.line}</LineChip>
        <span>{leg.headsign}</span>
      </span>
    ),
    description: (
      <span className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
        <span>
          {leg.fromName} 乗車 → {leg.toName} 降車
        </span>
        <span aria-hidden="true">·</span>
        <span>{leg.stopCount}停</span>
        {leg.platform ? (
          <>
            <span aria-hidden="true">·</span>
            <span>のりば {leg.platform}</span>
          </>
        ) : null}
      </span>
    ),
    trailing:
      leg.segmentFareIc != null ? (
        <span className="text-xs tabular-nums text-muted-foreground">
          IC {fmtYen(leg.segmentFareIc)}
        </span>
      ) : undefined,
  };
}

/* ------------------------------------------------------------------ */
/* search bar (origin / destination + swap + time mode)               */
/* ------------------------------------------------------------------ */

type TimeMode = "depart" | "arrive";

function SearchBar({
  origin,
  destination,
  onSwap,
  timeMode,
  onTimeMode,
  timeValue,
}: {
  origin: string;
  destination: string;
  onSwap: () => void;
  timeMode: TimeMode;
  onTimeMode: (m: TimeMode) => void;
  timeValue: string;
}) {
  return (
    <section
      aria-label="検索条件"
      className="rounded-xl border bg-card p-3 shadow-sm"
    >
      <div className="flex items-stretch gap-2">
        {/* from / to stack */}
        <div className="min-w-0 flex-1">
          <div className="flex items-center gap-2 py-2">
            <IconMapPin className="size-4 shrink-0 text-muted-foreground" aria-hidden="true" />
            <span className="sr-only">出発地</span>
            <span className="truncate text-[15px] font-medium text-foreground">{origin}</span>
          </div>
          <Separator />
          <div className="flex items-center gap-2 py-2">
            <IconFlag className="size-4 shrink-0 text-primary" aria-hidden="true" />
            <span className="sr-only">目的地</span>
            <span className="truncate text-[15px] font-medium text-foreground">{destination}</span>
          </div>
        </div>
        {/* swap */}
        <div className="flex items-center">
          <Button
            variant="outline"
            size="icon"
            onClick={onSwap}
            aria-label="出発地と目的地を入れ替える"
            className="rounded-full"
          >
            <IconArrowsUpDown className="size-5" aria-hidden="true" />
          </Button>
        </div>
      </div>

      <div className="mt-3 flex items-center gap-2">
        <ToggleGroup
          type="single"
          value={timeMode}
          disallowEmpty
          onValueChange={(v) => onTimeMode(v as TimeMode)}
          aria-label="時刻の基準"
          className="justify-start"
        >
          <ToggleGroupItem value="depart" size="sm" aria-label="出発時刻で検索">
            出発
          </ToggleGroupItem>
          <ToggleGroupItem value="arrive" size="sm" aria-label="到着時刻で検索">
            到着
          </ToggleGroupItem>
        </ToggleGroup>
        <span className="inline-flex items-center gap-1 text-sm tabular-nums text-muted-foreground">
          <IconClock className="size-4" aria-hidden="true" />
          {timeValue} {timeMode === "depart" ? "出発" : "到着"}
        </span>
      </div>
    </section>
  );
}

/* ------------------------------------------------------------------ */
/* candidate row                                                       */
/* ------------------------------------------------------------------ */

function CandidateRow({
  c,
  selected,
  onSelect,
}: {
  c: RouteCandidate;
  selected: boolean;
  onSelect: () => void;
}) {
  const recommended = c.badges.includes("recommended");
  return (
    <ListCard
      selected={selected}
      severity={recommended ? "info" : undefined}
      onSelect={onSelect}
      leading={
        <div className="flex w-12 flex-col items-center gap-1">
          {c.lines.map((ln, i) => (
            <LineChip key={i}>{ln}</LineChip>
          ))}
        </div>
      }
      title={
        <span className="flex items-baseline gap-1.5 tabular-nums">
          <span className="text-lg font-bold">{c.departAt}</span>
          <IconArrowRight className="size-4 self-center text-muted-foreground" aria-hidden="true" />
          <span className="text-lg font-bold">{c.arriveAt}</span>
          <span className="ml-1 text-sm font-normal text-muted-foreground">
            （{c.durationMin}分）
          </span>
        </span>
      }
      description={
        <span className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
          <span>{transferLabel(c.transfers)}</span>
          <span aria-hidden="true">·</span>
          <span>{c.fromStop}</span>
        </span>
      }
      tags={c.badges.map((b) => (
        <Badge key={b} variant={BADGE_LABEL[b].variant}>
          {BADGE_LABEL[b].label}
        </Badge>
      ))}
      meta={
        <span className="flex flex-col items-end gap-0.5">
          <span className="text-base font-bold tabular-nums text-foreground">
            IC {fmtYen(c.fareIc)}
          </span>
          {c.nextInMin != null ? (
            <span
              className={
                c.nextInMin <= 3
                  ? "tabular-nums text-warning"
                  : "tabular-nums text-muted-foreground"
              }
            >
              次のバス {c.nextInMin}分後
            </span>
          ) : null}
        </span>
      }
    />
  );
}

/* ------------------------------------------------------------------ */
/* detail (leg-by-leg + fare)                                          */
/* ------------------------------------------------------------------ */

function RouteDetail({
  c,
  saved,
  onToggleSave,
  onBackToList,
}: {
  c: RouteCandidate;
  saved: boolean;
  onToggleSave: () => void;
  onBackToList: () => void;
}) {
  const items = c.legs.map(legToItem);

  // 運賃内訳: per-ride segment + 合計（通し/IC）
  const rideLegs = c.legs.filter((l) => l.kind === "ride");
  const fareLines: AmountLine[] = rideLegs.map((l, i) => ({
    type: "line",
    label: `${i + 1}区間目　${l.line}（${l.fromName} → ${l.toName}）`,
    amount: l.segmentFareIc ?? 0,
    note: `${l.stopCount}停・IC運賃`,
  }));

  return (
    <div className="flex flex-col gap-4">
      <button
        type="button"
        onClick={onBackToList}
        className="inline-flex items-center gap-1 self-start rounded-md py-1 text-sm font-medium text-primary outline-none hover:underline focus-visible:ring-2 focus-visible:ring-ring"
      >
        <IconChevronRight className="size-4 rotate-180" aria-hidden="true" />
        経路候補へ戻る
      </button>

      {/* summary header */}
      <section
        aria-label="選択した経路の概要"
        className="rounded-xl border bg-card p-4"
      >
        <div className="flex items-center justify-between gap-2">
          <div className="flex flex-wrap gap-1.5">
            {c.badges.map((b) => (
              <Badge key={b} variant={BADGE_LABEL[b].variant}>
                {BADGE_LABEL[b].label}
              </Badge>
            ))}
          </div>
          {c.delayMin && c.delayMin > 0 ? (
            <Badge variant="warning" icon={<IconClock />}>
              遅延 約{c.delayMin}分
            </Badge>
          ) : (
            <Badge variant="success">定刻</Badge>
          )}
        </div>

        <div className="mt-3 flex items-baseline gap-2 tabular-nums">
          <span className="text-2xl font-bold">{c.departAt}</span>
          <IconArrowRight className="size-5 self-center text-muted-foreground" aria-hidden="true" />
          <span className="text-2xl font-bold">{c.arriveAt}</span>
        </div>
        <div className="mt-1 flex flex-wrap items-center gap-x-3 gap-y-1 text-sm text-muted-foreground">
          <span>所要 {c.durationMin}分</span>
          <span aria-hidden="true">·</span>
          <span>{transferLabel(c.transfers)}</span>
          <span aria-hidden="true">·</span>
          <span className="font-semibold text-foreground">IC {fmtYen(c.fareIc)}</span>
        </div>
        {c.nextInMin != null ? (
          <p
            className={`mt-2 text-sm font-medium ${
              c.nextInMin <= 3 ? "text-warning" : "text-foreground"
            }`}
          >
            次のバスは約 {c.nextInMin}分後（{c.fromStop}）に出発します
          </p>
        ) : null}
      </section>

      {/* leg-by-leg */}
      <section aria-label="経路の詳細（区間ごと）">
        <h2 className="mb-3 text-sm font-semibold text-foreground">経路の詳細</h2>
        <Itinerary items={items} />
      </section>

      {/* fare breakdown */}
      <section aria-label="運賃の内訳" className="rounded-xl border bg-card p-4">
        <h2 className="mb-2 text-sm font-semibold text-foreground">運賃の内訳</h2>
        <AmountBreakdown
          lines={fareLines}
          total={{ label: "合計（IC運賃・通し）", amount: c.fareIc }}
          formula={`現金運賃 ${fmtYen(c.fareCash)}／IC運賃 ${fmtYen(
            c.fareIc
          )}（小児半額）`}
          formatValue={fmtYen}
        />
      </section>

      {/* sticky actions */}
      <div className="sticky bottom-0 -mx-4 flex gap-2 border-t bg-background/95 px-4 py-3 backdrop-blur supports-[backdrop-filter]:bg-background/80">
        <Button
          variant="outline"
          size="lg"
          onClick={onToggleSave}
          aria-pressed={saved}
          className="shrink-0"
        >
          {saved ? (
            <IconBookmarkFilled className="size-5" aria-hidden="true" />
          ) : (
            <IconBookmark className="size-5" aria-hidden="true" />
          )}
          {saved ? "保存済み" : "保存"}
        </Button>
        <Button variant="primary" size="lg" className="flex-1">
          この経路で行く
        </Button>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* screen                                                              */
/* ------------------------------------------------------------------ */

export default function BusRouteSearchClient() {
  const [sort, setSort] = React.useState<SortKey>("fast");
  const [timeMode, setTimeMode] = React.useState<TimeMode>("depart");
  const [swapped, setSwapped] = React.useState(false);
  const [selectedId, setSelectedId] = React.useState<string | null>(null);
  const [saved, setSaved] = React.useState<Set<string>>(new Set());

  const origin = swapped ? DESTINATION : ORIGIN;
  const destination = swapped ? ORIGIN : DESTINATION;

  const sorted = React.useMemo(
    () => sortCandidates(CANDIDATES, sort),
    [sort]
  );

  const selected = selectedId
    ? CANDIDATES.find((c) => c.id === selectedId) ?? null
    : null;

  const toggleSave = (id: string) =>
    setSaved((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });

  const sortChips = SORT_TABS.map((t) => ({ value: t.value, label: t.label }));

  return (
    <div className="flex min-h-screen flex-col">
      <PageHeader
        title={selected ? "経路の詳細" : "経路検索"}
        subtitle={`${origin} → ${destination}`}
        align="center"
        onBack={selected ? () => setSelectedId(null) : undefined}
        backLabel="経路候補へ戻る"
        actions={
          <Button variant="ghost" size="icon" aria-label="再検索">
            <IconRefresh className="size-5" aria-hidden="true" />
          </Button>
        }
      />

      <div className="flex flex-1 flex-col gap-4 p-4">
        {selected ? (
          <RouteDetail
            c={selected}
            saved={saved.has(selected.id)}
            onToggleSave={() => toggleSave(selected.id)}
            onBackToList={() => setSelectedId(null)}
          />
        ) : (
          <>
            <SearchBar
              origin={origin}
              destination={destination}
              onSwap={() => setSwapped((s) => !s)}
              timeMode={timeMode}
              onTimeMode={setTimeMode}
              timeValue="10:00"
            />

            {/* sort bar */}
            <div>
              <h2 className="sr-only">並び替え</h2>
              <FilterChips
                items={sortChips}
                value={sort}
                onValueChange={(v) => setSort(v as SortKey)}
                aria-label="経路候補の並び替え"
              />
            </div>

            {/* candidate list */}
            <section aria-label="経路候補" className="flex flex-col gap-3">
              <p className="text-xs text-muted-foreground" aria-live="polite">
                経路候補 {sorted.length}件・{SORT_TABS.find((t) => t.value === sort)?.label}
              </p>
              {sorted.map((c) => (
                <CandidateRow
                  key={c.id}
                  c={c}
                  selected={false}
                  onSelect={() => setSelectedId(c.id)}
                />
              ))}
            </section>
          </>
        )}
      </div>
    </div>
  );
}

