// 横浜市営/東急バス エリアの実在風データ（渋谷駅 → 等々力 ほか）。
// All UI strings live close to the data so the screen reads like a real product.

export type SortKey = "fast" | "cheap" | "fewTransfers";

/** 経路候補（一覧の1行サマリ） */
export interface RouteCandidate {
  id: string;
  /** 出発時刻 "HH:MM" */
  departAt: string;
  /** 到着時刻 "HH:MM" */
  arriveAt: string;
  /** 所要（分） */
  durationMin: number;
  /** 乗換回数（0 = 直通） */
  transfers: number;
  /** IC運賃（円・通し） */
  fareIc: number;
  /** 現金運賃（円・通し） */
  fareCash: number;
  /** 主な系統（例: 渋66 → 東98） */
  lines: string[];
  /** 出発バス停 */
  fromStop: string;
  /** バッジ: おすすめ / 最速 / 最安 / 乗換少 */
  badges: ("recommended" | "fastest" | "cheapest" | "fewest")[];
  /** 次のバスまで（分）。null = 時刻指定検索でリアルタイム非該当 */
  nextInMin: number | null;
  /** 遅延（分）。0 / undefined = 定刻 */
  delayMin?: number;
  /** 詳細レグ */
  legs: Leg[];
}

export type LegKind = "walk" | "ride" | "wait";

export interface Leg {
  kind: LegKind;
  /** 開始時刻 */
  startAt?: string;
  /** 終了時刻 */
  endAt?: string;
  /** 所要（分） */
  durationMin: number;
  /** 乗車レグ: 系統名（渋66） */
  line?: string;
  /** 乗車レグ: 行き先（等々力行） */
  headsign?: string;
  /** 乗車/徒歩 の起点 */
  fromName?: string;
  /** 乗車/徒歩 の終点 */
  toName?: string;
  /** 乗車レグ: 経由停留所数 */
  stopCount?: number;
  /** 乗車レグ: のりば（◯番） */
  platform?: string;
  /** 乗車レグ: 区間IC運賃（円） */
  segmentFareIc?: number;
  /** 乗換待ちレグ: 遅延（分） */
  delayMin?: number;
  /** 補足 */
  note?: string;
}

export const ORIGIN = "渋谷駅";
export const DESTINATION = "等々力";

export const SORT_TABS: { value: SortKey; label: string }[] = [
  { value: "fast", label: "速い順" },
  { value: "cheap", label: "安い順" },
  { value: "fewTransfers", label: "乗換少" },
];

