const FASTEST_ID = "r2";
const CHEAPEST_ID = "r2";

/** Sort the candidate list per the active tab (stable, value-driven). */
export function sortCandidates(list: RouteCandidate[], key: SortKey): RouteCandidate[] {
  const copy = [...list];
  switch (key) {
    case "fast":
      return copy.sort((a, b) => a.durationMin - b.durationMin || a.fareIc - b.fareIc);
    case "cheap":
      return copy.sort((a, b) => a.fareIc - b.fareIc || a.durationMin - b.durationMin);
    case "fewTransfers":
      return copy.sort(
        (a, b) => a.transfers - b.transfers || a.durationMin - b.durationMin
      );
  }
}

export { FASTEST_ID, CHEAPEST_ID };
